import React from 'react';
import Button from '../1_atoms/Button';
import './BlogHeader.css';

function BlogHeader({
  categories,
  searchTerm,
  selectedCategory,
  onSearchChange,
  onCategoryChange,
}) {
  return (
    <header className="blog-header">
      <div className="blog-header__content">
        <div className="blog-header__copy">
          <p className="blog-header__eyebrow">Р‘Р»РѕРі InsureKids</p>
          <h1>РЈС‡РёРјСЃСЏ РїРѕРЅРёРјР°С‚СЊ СЃС‚СЂР°С…РѕРІР°РЅРёРµ РЅР° РїРѕРЅСЏС‚РЅС‹С… Р¶РёР·РЅРµРЅРЅС‹С… РїСЂРёРјРµСЂР°С…</h1>
          <p>
            РС‰Рё С‚РµРјСѓ РїРѕ СЃРёС‚СѓР°С†РёРё, С„РёР»СЊС‚СЂСѓР№ СЃС‚Р°С‚СЊРё РїРѕ РєР°С‚РµРіРѕСЂРёСЏРј Рё РїРµСЂРµС…РѕРґРё Рє С‚РµРј РјР°С‚РµСЂРёР°Р»Р°Рј,
            РєРѕС‚РѕСЂС‹Рµ СЂРµР°Р»СЊРЅРѕ РїСЂРёРіРѕРґСЏС‚СЃСЏ РІ РёРіСЂРµ Рё РІ Р¶РёР·РЅРё.
          </p>
        </div>

        <div className="blog-header__controls">
          <form className="blog-search" onSubmit={(event) => event.preventDefault()}>
            <input
              type="text"
              placeholder="РљР°РєРѕР№ Сѓ РІР°СЃ РІРѕРїСЂРѕСЃ?"
              value={searchTerm}
              onChange={(event) => onSearchChange(event.target.value)}
              className="blog-search__input"
            />
            <Button type="submit">РџРѕРёСЃРє</Button>
          </form>

          <div className="blog-filters">
            <span className="blog-filters__label">РљР°С‚РµРіРѕСЂРёРё</span>
            <div className="blog-filters__buttons">
              {categories.map((category) => (
                <button
                  key={category}
                  type="button"
                  className={`blog-filter-button ${selectedCategory === category ? 'active' : ''}`}
                  onClick={() => onCategoryChange(category)}
                >
                  {category}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    </header>
  );
}

export default BlogHeader;
